### Task 8: Workspace-Aware Search Output

### Task 9: Integration Test — Workspace End-to-End

Create an integration test that exercises the full workspace flow: create config, scaffold, ingest from a local repo, search across namespaces.

**Files:**
- Create: `tests/integration/workspace_e2e_test.rs`

**Step 1: Write the integration test**

```rust
//! M2.1 Workspace integration test
//! Tests: config → scaffold → ingest → cross-namespace search

use corvia_common::config::{CorviaConfig, WorkspaceConfig, RepoConfig};
use corvia_kernel::traits::{QueryableStore, InferenceEngine};
use corvia_kernel::lite_store::LiteStore;
use anyhow::Result;
use async_trait::async_trait;
use std::path::Path;
use tempfile::tempdir;

struct MockEngine;

#[async_trait]
impl InferenceEngine for MockEngine {
    async fn embed(&self, _text: &str) -> Result<Vec<f32>> {
        Ok(vec![1.0, 0.0, 0.0])
    }
    async fn embed_batch(&self, texts: &[String]) -> Result<Vec<Vec<f32>>> {
        Ok(texts.iter().map(|_| vec![1.0, 0.0, 0.0]).collect())
    }
    fn dimensions(&self) -> usize {
        3
    }
}

fn make_workspace_config(repos: Vec<RepoConfig>) -> CorviaConfig {
    let mut config = CorviaConfig::default();
    config.project.name = "test-workspace".into();
    config.project.scope_id = "test".into();
    config.embedding.dimensions = 3;
    config.workspace = Some(WorkspaceConfig {
        repos_dir: "repos".into(),
        repos,
    });
    config
}

#[tokio::test]
async fn test_workspace_config_roundtrip_and_detection() {
    let dir = tempdir().unwrap();
    let config = make_workspace_config(vec![
        RepoConfig {
            name: "repo-a".into(),
            url: "https://github.com/org/repo-a".into(),
            local: None,
            namespace: "alpha".into(),
        },
    ]);

    assert!(config.is_workspace());
    let path = dir.path().join("corvia.toml");
    config.save(&path).unwrap();

    let loaded = CorviaConfig::load(&path).unwrap();
    assert!(loaded.is_workspace());
    let ws = loaded.workspace.unwrap();
